import math

def e_value(rr: float) -> dict:
    ev = rr + math.sqrt(rr * (rr - 1))
    if ev > 3:   verdict = 'robust'
    elif ev > 1.5: verdict = 'fragile'
    else:          verdict = 'not-definitive'
    return {'rr': rr, 'e_value': round(ev, 3),
            'verdict': verdict}

print(e_value(2.1))
# {'rr': 2.1, 'e_value': 3.293, 'verdict': 'robust'}
print(e_value(1.3))
# {'rr': 1.3, 'e_value': 1.635, 'verdict': 'fragile'}
